// NOTE COPIED THIS OUT OF TASK...
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}

	if (oldValue != ""){
		if (g_scratchpad.calchaschildren>0){
			g_form.addInfoMessage(getMessage('Tasker - Changing the Tasking Authority Updates All Descendant Tasks'));
		}
	}

	var OUPermissions  = new GlideAjax('ClientUserInfoScripts');
	OUPermissions.addParam('sysparm_name','isOUExternalTA');
	OUPermissions.addParam("OU", g_form.getValue('tasking_authority'));
	var answer2 = false;
	// call script include to determine if this user is a tasking authority of the primary assignee OU.
	OUPermissions.getXML(f_returnIsTAExternal);
	// comment 
	function f_returnIsTAExternal(response){
		var answer2 = response.responseXML.documentElement.getAttribute("answer");
		var isTAExternal = answer2 == 'true';
		var blnChangeAssignment = true;
		if (newValue) {
			if (newValue != '' && !isTAExternal){
				// STRY0071489 If new setting for system property definie if Primary Office Must Match Internal Tasking Authority
				if(g_scratchpad.primary_office_must_match_Internal_tasking_authority == 'true'){
					g_form.setValue('primary_office',newValue);
					g_form.setReadOnly('primary_office',true);
				}
				g_form.hideFieldMsg('tasking_authority');
			}
			else{
				g_form.setReadOnly('primary_office',false);
				// STRY0074601
				g_form.showFieldMsg("tasking_authority", "The OU selected is an Organizational Unit external to your organization.", "info");
			}
		}
	}
}
